import math

def count_portfolios(n_assets, k_select):
    """
    Calculate the number of possible portfolios when selecting
    exactly k assets from n available assets.
    """
    return math.comb(n_assets, k_select)

def estimate_solve_time(n_portfolios, portfolios_per_second=1000000):
    """
    Estimate time to enumerate all portfolios.
    """
    seconds = n_portfolios / portfolios_per_second

    if seconds < 60:
        return f'{seconds:.2f} seconds'
    elif seconds < 3600:
        return f'{seconds/60:.2f} minutes'
    elif seconds < 86400:
        return f'{seconds/3600:.2f} hours'
    elif seconds < 31536000:
        return f'{seconds/86400:.2f} days'
    else:
        years = seconds / 31536000
        if years > 1e10:
            return f'{years:.2e} years'
        return f'{years:.2f} years'

# Test cases
test_cases = [
    (20, 5),    # Small
    (50, 10),   # Medium
    (100, 20),  # Large
    (500, 50),  # Very large
]

for n, k in test_cases:
    count = count_portfolios(n, k)
    time_str = estimate_solve_time(count)
    print(f'C({n}, {k}) = {count:.2e} portfolios, time: {time_str}')
